INSERT INTO `about` (`id`, `title`, `subtitle`, `description`, `experience`, `goals`, `photo`, `youtube_url`, `facebook_url`, `twitter_url`, `telegram_url`, `email`, `updated_at`) VALUES ('1', 'Acerca de Mí', 'Ingeniero en Computación', 'Lenin Obregón Espinoza es Ingeniero en Computación de nacionalidad Nicaragüense de la tierra de lagos y volcanes montañas con pinares. Este canal es para mi memoria de aprendizaje y está orientado para aquellas personas que están iniciando el aprendizaje de infraestructuras, tengo mucha experiencia en el campo de Networking, Administración de Servidores en Entornos Linux y Windows, Monitoreo de Equipos de Comunicación entre otros.', 'Networking|Administración de Servidores en Entornos Linux y Windows|Monitoreo de Equipos de Comunicación', 'Promover el uso de tecnologías de información|Software libre|Área de Campus Networking|Ayudar a iniciados en el mundo IT', 'uploads/69cd89a19b22d.jpg', 'https://www.youtube.com/@leninobregonespinoza2160', '', '', '', 'lenin@ejemplo.com', '2026-04-01 15:09:53');
